import{_ as t,o as a,c as r,a2 as s}from"./chunks/framework.7R1OEGYz.js";const u=JSON.parse('{"title":"Directory","description":"","frontmatter":{},"headers":[],"relativePath":"using/directory.md","filePath":"using/directory.md"}'),i={name:"using/directory.md"};function o(n,e,d,h,c,l){return a(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="directory" tabindex="-1">Directory <a class="header-anchor" href="#directory" aria-label="Permalink to &quot;Directory&quot;">​</a></h1><p>The Directory is the trust surface. It lists verified humans with active up.id names. An unverified address cannot appear in it by construction.</p><h2 id="what-it-shows" tabindex="-1">What it shows <a class="header-anchor" href="#what-it-shows" aria-label="Permalink to &quot;What it shows&quot;">​</a></h2><p>Each row is a verified name: a red seal, the up.id name, and a truncated address. Your own row is marked. Hover a row to reveal a Send button that opens the Send screen with the recipient prefilled.</p><p>Search is server-side. The registry holds tens of thousands of names, so the guardian filters and returns a capped list per query.</p><h2 id="how-it-stays-honest" tabindex="-1">How it stays honest <a class="header-anchor" href="#how-it-stays-honest" aria-label="Permalink to &quot;How it stays honest&quot;">​</a></h2><p>The guardian builds the list from on-chain registration events. Every entry is checked at read time against two conditions: the name has an owner, and that owner has an active name. Both checks read live state, so a revoked or expired name drops out even though its registration event remains.</p><p>The registry has two traps that the guardian handles. It returns the zero address for unregistered names instead of reverting. And it reports an active name for the zero address. Both are rejected explicitly. See <a href="/docs/developers/findings.html">The findings</a>.</p>',8)])])}const m=t(i,[["render",o]]);export{u as __pageData,m as default};
